import { NextResponse } from 'next/server';

const BOT_WORKER_URL = process.env.BOT_INTERNAL_URL || 'http://localhost:3001';
const TIMEOUT_MS = 8000;

async function fetchWithTimeout(url, options = {}) {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS);
    try {
        const res = await fetch(url, { ...options, signal: controller.signal });
        clearTimeout(timeoutId);
        return res;
    } catch (err) {
        clearTimeout(timeoutId);
        throw err;
    }
}

export async function GET() {
    try {
        const res = await fetchWithTimeout(`${BOT_WORKER_URL}/api/bot/status`);
        const data = await res.json();
        return NextResponse.json(data);
    } catch (err) {
        // Worker indisponível — retornar estado "offline" amigável
        console.warn('[proxy/bot/status] Worker indisponível:', err.message);
        return NextResponse.json({
            ready: false,
            qrCode: '',
            status: 'offline',
            dbConnected: false,
            workerError: 'Motor do bot offline ou iniciando...',
        }, { status: 200 }); // 200 para não quebrar o frontend
    }
}
